arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty environment variables are no longer
        // treated as unset. GetEnvironmentVariable("MY_FLAG") now returns ""
        // instead of null when the variable is set to an empty string.
        // Use string.IsNullOrEmpty only when empty and unset should be equivalent;
        // here we intentionally distinguish them.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

