class ZipCreator
{
    void CreateArchive()
    {
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag in
        // the entry header for non-ASCII names. The legacy Java consumer reads
        // filenames as Shift-JIS, so it would misinterpret UTF-8-flagged entries.
        // Use the ZipFile.Open overload with an explicit Shift-JIS encoding to
        // write entry names the consumer expects and suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

